  var DEPOP_PICTURES_V2 = `${DEPOP_APP_BASE}api/v2/pictures/`;
  var DEPOP_ADDRESSES_V1 = `${DEPOP_APP_BASE}api/v1/addresses/`;
  var DEPOP_ADDRESSES_V1_QUERY = `${DEPOP_APP_BASE}api/v1/address/addresses/`;
  var DEPOP_POSTAL_ADDRESS = `${DEPOP_APP_BASE}api/v1/addresses/`;
  var DEPOP_PRODUCT_VIEW = `${DEPOP_APP_BASE}api/v2/product/userProductView/`;
  var DEPOP_SHOP_PRODUCTS = `${DEPOP_APP_BASE}api/v1/shop/products/`;
